#include <stdio.h>
#include <stdlib.h>
// Define the structure for a BST node
typedef struct Node {
    int val;
    struct Node* left;
    struct Node* right;
} Node;
// Function to create a new BST node
Node* createNode(int val) {
    Node* newNode = (Node*)malloc(sizeof(Node));
    if (!newNode) {
        printf("Memory error
");
        return NULL;
    }
    newNode->val = val;
    newNode->left = newNode->right = NULL;
    return newNode;
}
// Function to insert a node into the BST
Node* insertNode(Node* root, int val) {
    if (root == NULL) {
        root = createNode(val);
    } else if (val < root->val) {
        root->left = insertNode(root->left, val);
    } else if (val > root->val) {
        root->right = insertNode(root->right, val);
    }
    return root;
}
// Function to find the floor and ceil values in the BST
void findFloorAndCeil(Node* root, int key, int* floor, int* ceil) {
    *floor = -1;
    *ceil = -1;
    while (root) {
        if (root->val == key) {
            *floor = root->val;
            *ceil = root->val;
            break;
        } else if (root->val < key) {
            *floor = root->val;
            root = root->right;
        } else {
            *ceil = root->val;
            root = root->left;
        }
    }
}
int main() {
    int T;
    scanf("%d", &T);
    while (T--) {
        int N, K;
        scanf("%d %d", &N, &K);
        Node* root = NULL;
        for (int i = 0; i < N; i++) {
            int val;
            scanf("%d", &val);
            if (val != -1) {
                root = insertNode(root, val);
            }
        }
        int floor, ceil;
        findFloorAndCeil(root, K, &floor, &ceil);
        printf("%d %d\n", floor, ceil);
    }
    return 0;
}

