    static class Node {
        int val;
        Node left;
        Node right;
        Node(int val) {
            this.val = val;
            this.left = null;
            this.right = null;
        }
    }
    // Function to insert a node into the BST
    static Node insertNode(Node root, int val) {
        if (root == null) {
            root = new Node(val);
        } else if (val < root.val) {
            root.left = insertNode(root.left, val);
        } else if (val > root.val) {
            root.right = insertNode(root.right, val);
        }
        return root;
    }
    // Function to find the floor and ceil values in the BST
    static void findFloorAndCeil(Node root, int key, int[] floor, int[] ceil) {
        floor[0] = -1;
        ceil[0] = -1;
        while (root != null) {
            if (root.val == key) {
                floor[0] = root.val;
                ceil[0] = root.val;
                break;
            } else if (root.val < key) {
                floor[0] = root.val;
                root = root.right;
            } else {
                ceil[0] = root.val;
                root = root.left;
            }
        }
    }
    public static void main(String[] args) {
        Scanner sc = new Scanner(System.in);
        int T = sc.nextInt();
        while (T-- > 0) {
            int N = sc.nextInt();
            int K = sc.nextInt();
            Node root = null;
            for (int i = 0; i < N; i++) {
                int val = sc.nextInt();
